import { useState, useEffect, useMemo } from 'react';
import type { Aufgaben, Kategorien } from '@/types/app';
import { LivingAppsService, extractRecordId, createRecordUrl } from '@/services/livingAppsService';
import { APP_IDS } from '@/types/app';
import { format, parseISO, isToday, isBefore, startOfDay } from 'date-fns';
import { de } from 'date-fns/locale';
import { toast } from 'sonner';

import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Checkbox } from '@/components/ui/checkbox';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Skeleton } from '@/components/ui/skeleton';
import { Badge } from '@/components/ui/badge';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Toaster } from '@/components/ui/sonner';
import {
  Plus,
  AlertCircle,
  Clock,
  CheckCircle2,
  Pencil,
  Trash2,
  Settings,
  ListTodo,
} from 'lucide-react';

// Priority configuration
const PRIORITY_CONFIG = {
  sehr_hoch: { label: 'Sehr hoch', color: 'hsl(0 70% 50%)', order: 0 },
  hoch: { label: 'Hoch', color: 'hsl(25 90% 50%)', order: 1 },
  mittel: { label: 'Mittel', color: 'hsl(45 90% 50%)', order: 2 },
  niedrig: { label: 'Niedrig', color: 'hsl(175 50% 35%)', order: 3 },
} as const;

// Category color configuration
const CATEGORY_COLORS = {
  rot: 'hsl(0 70% 50%)',
  blau: 'hsl(210 70% 50%)',
  gruen: 'hsl(140 60% 40%)',
  orange: 'hsl(25 90% 50%)',
  lila: 'hsl(280 60% 50%)',
  grau: 'hsl(0 0% 50%)',
  gelb: 'hsl(45 90% 50%)',
} as const;

type PriorityKey = keyof typeof PRIORITY_CONFIG;
type CategoryColorKey = keyof typeof CATEGORY_COLORS;

// Progress Ring Component
function ProgressRing({ progress, size = 80, strokeWidth = 8 }: { progress: number; size?: number; strokeWidth?: number }) {
  const radius = (size - strokeWidth) / 2;
  const circumference = radius * 2 * Math.PI;
  const offset = circumference - (progress / 100) * circumference;

  return (
    <svg width={size} height={size} className="transform -rotate-90">
      <circle
        className="text-muted"
        strokeWidth={strokeWidth}
        stroke="currentColor"
        fill="transparent"
        r={radius}
        cx={size / 2}
        cy={size / 2}
      />
      <circle
        className="text-primary transition-all duration-500"
        strokeWidth={strokeWidth}
        strokeDasharray={circumference}
        strokeDashoffset={offset}
        strokeLinecap="round"
        stroke="currentColor"
        fill="transparent"
        r={radius}
        cx={size / 2}
        cy={size / 2}
      />
    </svg>
  );
}

// Loading skeleton
function LoadingState() {
  return (
    <div className="min-h-screen bg-background p-4 md:p-6">
      <div className="max-w-7xl mx-auto space-y-6">
        <div className="flex justify-between items-center">
          <Skeleton className="h-8 w-48" />
          <Skeleton className="h-10 w-32" />
        </div>
